CREATE OR REPLACE FUNCTION to_snumber (adc_amount bigint) RETURNS varchar AS $body$
BEGIN
  -- ใส่ คอมมา(,) คั่นหลักพัน และ ทศนิยม 2 ตำแหน่ง
  if coalesce(adc_amount::text, '') = '' or adc_amount = 0 then
    return '0.00';
  end if;
  return trim(both to_char(adc_amount,'999,999,999,999.99'));
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
